class Solution:
    def countCompleteComponents(self, n, edges):
        adj = [set() for _ in range(n)]
        for a, b in edges:
            adj[a].add(b)
            adj[b].add(a)
        visited = [False] * n
        count = 0
        for i in range(n):
            if visited[i]:
                continue
            comp = []
            stack = [i]
            visited[i] = True
            while stack:
                u = stack.pop()
                comp.append(u)
                for v in adj[u]:
                    if not visited[v]:
                        visited[v] = True
                        stack.append(v)
            ok = True
            for x in comp:
                for y in comp:
                    if x != y and y not in adj[x]:
                        ok = False
            if ok:
                count += 1
        return count

