class Solution:
    def countCompleteComponents(self, n, edges):
        parent = list(range(n))
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        def union(a, b):
            ra, rb = find(a), find(b)
            if ra != rb:
                parent[ra] = rb
        for a, b in edges:
            union(a, b)
        verts = {}
        edgs = {}
        for i in range(n):
            r = find(i)
            verts[r] = verts.get(r, 0) + 1
        for a, b in edges:
            r = find(a)
            edgs[r] = edgs.get(r, 0) + 1
        count = 0
        for root, v in verts.items():
            if edgs.get(root, 0) == v * (v - 1) // 2:
                count += 1
        return count

