var countCompleteComponents = function(n, edges) {
    const parent = Array.from({ length: n }, (_, i) => i);
    function find(x) {
        while (parent[x] !== x) {
            parent[x] = parent[parent[x]];
            x = parent[x];
        }
        return x;
    }
    function union(a, b) {
        const ra = find(a), rb = find(b);
        if (ra !== rb) parent[ra] = rb;
    }
    for (const [a, b] of edges) union(a, b);
    const verts = new Map();
    const edgs = new Map();
    for (let i = 0; i < n; i++) {
        const r = find(i);
        verts.set(r, (verts.get(r) || 0) + 1);
    }
    for (const [a] of edges) {
        const r = find(a);
        edgs.set(r, (edgs.get(r) || 0) + 1);
    }
    let count = 0;
    for (const [root, v] of verts) {
        if ((edgs.get(root) || 0) === (v * (v - 1)) / 2) count++;
    }
    return count;
};
